'use client';

import React, { useState, useRef } from 'react';
import Link from 'next/link';
import { Mail, Lock, ChevronRight, User, AlertCircle, CheckCircle2, Eye, EyeOff } from 'lucide-react';
import Button from '@/src/components/ui/Button';
import * as authService from '@/src/services/authService';
import { useAuth } from '@/src/context/AuthContext';
import { useRouter, useSearchParams } from 'next/navigation';

// Internal Helper Component for Form Fields
const FieldWrapper = ({
  label,
  required,
  children,
  field,
  touched,
  errors,
  icon: Icon,
}: {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  field: string;
  touched: Record<string, boolean>;
  errors: Record<string, string>;
  icon: any;
}) => {
  const hasError = touched[field] && errors[field];
  return (
    <div className="space-y-1.5 relative group">
      <label
        className={`text-[10px] font-bold uppercase tracking-widest pl-1 transition-colors ${hasError ? 'text-red-500' : 'text-gray-400'}`}
      >
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <div className="relative">
        <Icon
          className={`absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 transition-colors z-10 ${hasError ? 'text-red-500' : 'text-gray-400 group-focus-within:text-primary'}`}
        />
        {children}
      </div>
      {hasError && (
        <p className="text-[11px] text-red-500 font-bold animate-in fade-in slide-in-from-top-1 ml-1">
          {errors[field]}
        </p>
      )}
    </div>
  );
};

export default function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [loading, setLoading] = useState(false);
  const { setToken } = useAuth();
  const router = useRouter();
  const searchParams = useSearchParams();
  const passwordRef = useRef<HTMLInputElement>(null);

  const justRegistered = searchParams.get('registered') === 'true';

  const handleUsernameKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      e.stopPropagation();
      passwordRef.current?.focus();
    }
  };

  const validate = (overrides?: Record<string, string>) => {
    const data = { username, password, ...overrides };
    const errs: Record<string, string> = {};

    if (!data.username.trim()) {
      errs.username = 'Vui lòng nhập email hoặc tên đăng nhập.';
    }

    if (!data.password) {
      errs.password = 'Vui lòng nhập mật khẩu.';
    }

    setFieldErrors(errs);
    return errs;
  };

  const handleBlur = (field: string) => {
    setTouched((prev) => ({ ...prev, [field]: true }));
    validate();
  };

  const handleChange = (field: string, value: string) => {
    if (field === 'username') setUsername(value);
    else setPassword(value);

    if (touched[field]) {
      validate({ [field]: value });
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const allTouched = { username: true, password: true };
    setTouched(allTouched);

    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setError('Vui lòng điền đầy đủ thông tin đăng nhập.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await authService.login(username.trim(), password);
      if (response.success && response.data?.token) {
        const user = response.data.user;
        setToken(response.data.token, user);
        router.push('/dashboard');
      } else {
        setError(response.message || 'Đăng nhập thất bại. Vui lòng thử lại.');
      }
    } catch (err: any) {
      setError(err.message || 'Đăng nhập thất bại. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  };

  const getInputClass = (fieldName: string) => {
    const baseClass =
      'w-full pl-12 pr-4 py-4 bg-gray-50 border rounded-2xl font-medium outline-none transition-all text-gray-900';
    if (touched[fieldName] && fieldErrors[fieldName]) {
      return `${baseClass} border-red-500 bg-red-50/30 text-red-900 placeholder-red-300`;
    }
    return `${baseClass} border-gray-100 focus:border-primary/20 focus:bg-white`;
  };

  return (
    <div className="bg-white rounded-3xl shadow-2xl p-10 flex flex-col gap-8 relative overflow-hidden">
      {/* Login Header */}
      <div className="flex flex-col gap-2">
        <div className="w-12 h-12 bg-primary-soft rounded-xl flex items-center justify-center text-primary mb-4">
          <User className="w-6 h-6" />
        </div>
        <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">Đăng nhập</h2>
        <p className="text-gray-500 font-medium">Chào mừng bạn quay trở lại!</p>
      </div>

      {justRegistered && !error && (
        <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2">
          <CheckCircle2 className="w-5 h-5 flex-shrink-0" />
          Đăng ký thành công! Vui lòng đăng nhập bằng tài khoản vừa tạo.
        </div>
      )}

      {error && (
        <div className="bg-red-50 border border-red-100 text-red-600 px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 flex-shrink-0" />
          {error}
        </div>
      )}

      {/* Form Fields */}
      <form className="space-y-4" onSubmit={handleSubmit} noValidate>
        <FieldWrapper
          label="Email hoặc tên đăng nhập"
          required
          field="username"
          touched={touched}
          errors={fieldErrors}
          icon={Mail}
        >
          <input
            type="text"
            placeholder="admin@qlhv.vn"
            value={username}
            onChange={(e) => handleChange('username', e.target.value)}
            onBlur={() => handleBlur('username')}
            onKeyDown={handleUsernameKeyDown}
            className={getInputClass('username')}
          />
        </FieldWrapper>

        <FieldWrapper label="Mật khẩu" required field="password" touched={touched} errors={fieldErrors} icon={Lock}>
          <div className="relative group/passwd">
            <input
              type={showPassword ? 'text' : 'password'}
              placeholder="••••••••"
              value={password}
              ref={passwordRef}
              onChange={(e) => handleChange('password', e.target.value)}
              onBlur={() => handleBlur('password')}
              className={getInputClass('password')}
            />
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-4 top-1/2 -translate-y-1/2 p-2 text-gray-400 hover:text-primary transition-colors focus:outline-none z-20"
              tabIndex={-1}
            >
              {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
          </div>
        </FieldWrapper>
        <div className="flex justify-end pr-1">
          <Link href="#" className="text-[10px] font-bold text-primary uppercase tracking-widest hover:underline mt-1">
            Quên mật khẩu?
          </Link>
        </div>

        <Button
          fullWidth
          size="lg"
          type="submit"
          disabled={loading}
          className="rounded-2xl mt-6 py-4 flex items-center gap-2 group justify-center shadow-xl shadow-primary/20"
        >
          {loading ? (
            'Đăng nhập...'
          ) : (
            <>
              Tiếp tục <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </>
          )}
        </Button>
      </form>

      {/* Footer */}
      <div className="text-center pt-4">
