'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import {
  User,
  Phone,
  Mail,
  Lock,
  ChevronRight,
  GraduationCap,
  AlertCircle,
  Fingerprint,
  MapPin,
  IdCard,
  UserCircle,
} from 'lucide-react';
import Button from '@/src/components/ui/Button';
import * as authService from '@/src/services/authService';
import { useRouter } from 'next/navigation';

// Internal Helper Component for Form Fields
const FieldWrapper = ({
  label,
  required,
  children,
  field,
  touched,
  errors,
  icon: Icon,
}: {
  label: string;
  required?: boolean;
  children: React.ReactNode;
  field: string;
  touched: Record<string, boolean>;
  errors: Record<string, string>;
  icon: any;
}) => {
  const hasError = touched[field] && errors[field];
  return (
    <div className="space-y-1.5 relative group">
      <label
        className={`text-[10px] font-bold uppercase tracking-widest pl-1 transition-colors ${hasError ? 'text-red-500' : 'text-gray-400'}`}
      >
        {label} {required && <span className="text-red-500">*</span>}
      </label>
      <div className="relative">
        <Icon
          className={`absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 transition-colors z-10 ${hasError ? 'text-red-500' : 'text-gray-400 group-focus-within:text-primary'}`}
        />
        {children}
      </div>
      {hasError && (
        <p className="text-[11px] text-red-500 font-bold animate-in fade-in slide-in-from-top-1 ml-1">
          {errors[field]}
        </p>
      )}
    </div>
  );
};

export default function RegisterPage() {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [username, setUsername] = useState('');
  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [identityCard, setIdentityCard] = useState('');
  const [address, setAddress] = useState('');
  const [role, setRole] = useState('student');

  const [error, setError] = useState<string | null>(null);
  const [fieldErrors, setFieldErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const validate = (overrides?: Record<string, string>) => {
    const data = {
      firstName,
      lastName,
      username,
      phone,
      email,
      password,
      identityCard,
      address,
      role,
      ...overrides,
    };

    const errs: Record<string, string> = {};

    if (!data.firstName.trim()) errs.firstName = 'Vui lòng nhập tên.';
    if (!data.lastName.trim()) errs.lastName = 'Vui lòng nhập họ và đệm.';
    if (!data.username.trim()) errs.username = 'Vui lòng nhập tên đăng nhập.';

    if (!data.phone.trim()) {
      errs.phone = 'Vui lòng nhập số điện thoại.';
    } else if (!/^\d{10}$/.test(data.phone.trim().replace(/\s/g, ''))) {
      errs.phone = 'Số điện thoại phải có đúng 10 chữ số.';
    }

    if (!data.email.trim()) {
      errs.email = 'Vui lòng nhập email.';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email.trim())) {
      errs.email = 'Email không hợp lệ.';
    }

    if (!data.password) {
      errs.password = 'Vui lòng nhập mật khẩu.';
    } else if (data.password.length < 6) {
      errs.password = 'Mật khẩu phải có ít nhất 6 ký tự.';
    }

    if (!data.identityCard.trim()) {
      errs.identityCard = 'Vui lòng nhập số CCCD / CMND.';
    } else if (!/^\d{12}$/.test(data.identityCard.trim())) {
      errs.identityCard = 'CCCD không hợp lệ (phải có đúng 12 chữ số).';
    }

    if (!data.address.trim()) errs.address = 'Vui lòng nhập địa chỉ.';
    if (!data.role) errs.role = 'Vui lòng chọn vai trò.';

    setFieldErrors(errs);
    return errs;
  };

  const handleBlur = (field: string) => {
    setTouched((prev) => ({ ...prev, [field]: true }));
    validate();
  };

  const handleChange = (field: string, value: string) => {
    const setters: Record<string, (v: string) => void> = {
      firstName: setFirstName,
      lastName: setLastName,
      username: setUsername,
      phone: setPhone,
      email: setEmail,
      password: setPassword,
      identityCard: setIdentityCard,
      address: setAddress,
      role: setRole,
    };

    setters[field](value);
    if (touched[field]) {
      validate({ [field]: value });
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Mark all as touched
    const allTouched = {
      firstName: true,
      lastName: true,
      username: true,
      phone: true,
      email: true,
      password: true,
      identityCard: true,
      address: true,
      role: true,
    };
    setTouched(allTouched);

    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setError('Vui lòng kiểm tra lại thông tin đăng ký.');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      const response = await authService.register({
        username: username.trim(),
        password,
        first_name: firstName.trim(),
        last_name: lastName.trim(),
        email: email.trim(),
        phone: phone.trim().replace(/\s/g, ''),
        address: address.trim(),
        identity_card: identityCard.trim(),
        role: role,
      });

      if (response.success) {
        router.push('/login?registered=true');
      } else {
        if (response.errors && Array.isArray(response.errors)) {
          const mappedErrors: Record<string, string> = {};
          response.errors.forEach((err: any) => {
            const path = err.path || '';
            if (path.includes('username')) mappedErrors.username = err.message;
            if (path.includes('phone')) mappedErrors.phone = err.message;
            if (path.includes('email')) mappedErrors.email = err.message;
            if (path.includes('password')) mappedErrors.password = err.message;
            if (path.includes('first_name')) mappedErrors.firstName = err.message;
            if (path.includes('last_name')) mappedErrors.lastName = err.message;
            if (path.includes('identity_card')) mappedErrors.identityCard = err.message;
            if (path.includes('address')) mappedErrors.address = err.message;
            if (path.includes('role')) mappedErrors.role = err.message;
          });
          setFieldErrors(mappedErrors);
        }
        setError(response.message || 'Đăng ký thất bại. Vui lòng thử lại.');
      }
    } catch (err: any) {
      setError(err.message || 'Đăng ký thất bại. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  };

  const getInputClass = (fieldName: string) => {
    const baseClass =
      'w-full pl-12 pr-4 py-4 bg-gray-50 border rounded-2xl font-medium outline-none transition-all text-gray-900';
    if (touched[fieldName] && fieldErrors[fieldName]) {
      return `${baseClass} border-red-500 bg-red-50/30 text-red-900 placeholder-red-300`;
    }
    return `${baseClass} border-gray-100 focus:border-primary/20 focus:bg-white`;
  };

  return (
    <div className="bg-white rounded-3xl shadow-2xl p-10 flex flex-col gap-8 relative overflow-hidden">
      {/* Header Section */}
      <div className="flex flex-col gap-2">
        <div className="w-12 h-12 bg-primary-soft rounded-xl flex items-center justify-center text-primary mb-4">
          <GraduationCap className="w-6 h-6" />
        </div>
        <h2 className="text-3xl font-extrabold text-gray-900 tracking-tight">Đăng ký</h2>
        <p className="text-gray-500 font-medium">Bắt đầu hành trình của bạn ngay hôm nay!</p>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-100 text-red-600 px-4 py-3 rounded-xl flex items-center gap-3 text-sm font-medium animate-in fade-in slide-in-from-top-2">
          <AlertCircle className="w-5 h-5 flex-shrink-0" />
          {error}
        </div>
      )}

      {/* Form Section */}
      <form className="space-y-4" onSubmit={handleSubmit} noValidate>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <FieldWrapper label="Họ và đệm" required field="lastName" touched={touched} errors={fieldErrors} icon={User}>
            <input
              type="text"
              placeholder="Nguyễn Văn"
              className={getInputClass('lastName')}
              value={lastName}
              onChange={(e) => handleChange('lastName', e.target.value)}
              onBlur={() => handleBlur('lastName')}
              required
            />
          </FieldWrapper>

          <FieldWrapper label="Tên" required field="firstName" touched={touched} errors={fieldErrors} icon={User}>
            <input
              type="text"
              placeholder="An"
              className={getInputClass('firstName')}
              value={firstName}
              onChange={(e) => handleChange('firstName', e.target.value)}
              onBlur={() => handleBlur('firstName')}
              required
            />
          </FieldWrapper>

          <FieldWrapper
            label="Tên đăng nhập"
            required
            field="username"
            touched={touched}
            errors={fieldErrors}
            icon={Fingerprint}
          >
            <input
              type="text"
              placeholder="username123"
              className={getInputClass('username')}
              value={username}
              onChange={(e) => handleChange('username', e.target.value)}
              onBlur={() => handleBlur('username')}
              required
            />
          </FieldWrapper>

          <FieldWrapper
            label="CCCD / CMND"
            required
            field="identityCard"
            touched={touched}
            errors={fieldErrors}
            icon={IdCard}
          >
            <input
              type="text"
              placeholder="012345678901"
              className={getInputClass('identityCard')}
              value={identityCard}
              onChange={(e) => handleChange('identityCard', e.target.value)}
              onBlur={() => handleBlur('identityCard')}
              required
            />
          </FieldWrapper>

          <FieldWrapper
            label="Số điện thoại"
            required
            field="phone"
            touched={touched}
            errors={fieldErrors}
            icon={Phone}
          >
            <input
              type="tel"
              placeholder="0912 345 678"
              className={getInputClass('phone')}
              value={phone}
              onChange={(e) => handleChange('phone', e.target.value)}
              onBlur={() => handleBlur('phone')}
              required
            />
          </FieldWrapper>

          <FieldWrapper
            label="Email liên lạc"
            required
            field="email"
            touched={touched}
            errors={fieldErrors}
            icon={Mail}
          >
            <input
              type="email"
              placeholder="an.nguyenv@gmail.com"
              className={getInputClass('email')}
              value={email}
              onChange={(e) => handleChange('email', e.target.value)}
              onBlur={() => handleBlur('email')}
              required
            />
          </FieldWrapper>

          <FieldWrapper label="Vai trò" required field="role" touched={touched} errors={fieldErrors} icon={UserCircle}>
            <select
              value={role}
              className={`${getInputClass('role')} appearance-none`}
              onChange={(e) => handleChange('role', e.target.value)}
              onBlur={() => handleBlur('role')}
              required
            >
              <option value="student">Học viên</option>
              <option value="teacher">Giáo viên</option>
              <option value="staff">Nhân viên</option>
              <option value="sale">Sale</option>
            </select>
          </FieldWrapper>

          <FieldWrapper label="Mật khẩu" required field="password" touched={touched} errors={fieldErrors} icon={Lock}>
            <input
              type="password"
              placeholder="••••••••"
              className={getInputClass('password')}
              value={password}
              onChange={(e) => handleChange('password', e.target.value)}
              onBlur={() => handleBlur('password')}
              required
            />
          </FieldWrapper>
        </div>

        <FieldWrapper label="Địa chỉ" required field="address" touched={touched} errors={fieldErrors} icon={MapPin}>
          <input
            type="text"
            placeholder="123 Đường ABC, Quận XYZ, TP.HCM"
            className={getInputClass('address')}
            value={address}
            onChange={(e) => handleChange('address', e.target.value)}
            onBlur={() => handleBlur('address')}
            required
          />
        </FieldWrapper>

        <Button
          fullWidth
          size="lg"
          type="submit"
          disabled={loading}
          className="rounded-2xl mt-6 py-4 flex items-center gap-2 group justify-center shadow-xl shadow-primary/20"
        >
          {loading ? (
            'Đang tạo tài khoản...'
          ) : (
            <>
              Tạo tài khoản <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </>
          )}
        </Button>
      </form>

      {/* Footer */}
      <div className="text-center pt-4">
        <p className="text-sm text-gray-500 font-medium">
          Đã có tài khoản?{' '}
          <Link href="/login" className="text-primary font-bold hover:underline">
            Đăng nhập ngay
          </Link>
        </p>
      </div>

      <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -mr-16 -mt-16"></div>
      <div className="absolute bottom-0 left-0 w-24 h-24 bg-primary/5 rounded-full -ml-12 -mb-12"></div>
    </div>
  );
}

