import { MetadataRoute } from 'next';

export default function sitemap(): MetadataRoute.Sitemap {
  const baseUrl = 'https://qlhv-driving.com';
  const now = new Date();

  const routes = [
    { url: '', priority: 1.0, changefreq: 'daily' as const },
    { url: '/dashboard', priority: 0.9, changefreq: 'daily' as const },
    { url: '/courses', priority: 0.8, changefreq: 'weekly' as const },
    { url: '/students', priority: 0.8, changefreq: 'daily' as const },
    { url: '/sat-hach', priority: 0.7, changefreq: 'weekly' as const },
    { url: '/graduation-exam', priority: 0.7, changefreq: 'weekly' as const },
    { url: '/schedules', priority: 0.7, changefreq: 'weekly' as const },
    { url: '/tuition', priority: 0.6, changefreq: 'weekly' as const },
    { url: '/exam-batches', priority: 0.6, changefreq: 'weekly' as const },
    { url: '/practice', priority: 0.6, changefreq: 'weekly' as const },
    { url: '/progress', priority: 0.6, changefreq: 'weekly' as const },
    { url: '/notifications', priority: 0.5, changefreq: 'weekly' as const },
    { url: '/help', priority: 0.5, changefreq: 'monthly' as const },
  ];

  return routes.map(({ url, priority, changefreq }) => ({
    url: `${baseUrl}${url}`,
