          </div>
        </FieldWrapper>
        <div className="flex justify-end pr-1">
          <Link href="#" className="text-[10px] font-bold text-primary uppercase tracking-widest hover:underline mt-1">
            Quên mật khẩu?
          </Link>
        </div>

        <Button
          fullWidth
          size="lg"
          type="submit"
          disabled={loading}
          className="rounded-2xl mt-6 py-4 flex items-center gap-2 group justify-center shadow-xl shadow-primary/20"
        >
          {loading ? (
            'Đăng nhập...'
          ) : (
            <>
              Tiếp tục <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
            </>
          )}
        </Button>
      </form>

      {/* Footer */}
      <div className="text-center pt-4">
        <p className="text-sm text-gray-500 font-medium">
          Bạn chưa có tài khoản?{' '}
          <Link href="/register" className="text-primary font-bold hover:underline">
            Đăng ký ngay
          </Link>
        </p>
      </div>

      <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -mr-16 -mt-16"></div>
      <div className="absolute bottom-0 left-0 w-24 h-24 bg-primary/5 rounded-full -ml-12 -mb-12"></div>
    </div>
  );
}

